1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote", () => {
6	    // --- Empty / single item ---
7	    it.todo("should return 5 G for an empty item list (processing fee only)");
8	    it.todo("should return base premium plus fee for a single sword");
9	    it.todo("should return base premium plus fee for a single amulet");
10	    it.todo("should return base premium plus fee for a single staff");
11	    it.todo("should return base premium plus fee for a single potion");
12	
13	    // --- Components ---
14	    it.todo("should return 25 G base premium per component for 2 runes");
15	    it.todo("should return 60 G base premium for a building block of exactly 3 alike components");
16	    it.todo("should return 25 G per component with no block discount for 4 alike components");
17	    it.todo("should return separate block premiums for 3 runes and 3 moonstones");
18	    it.todo("should not apply block discount for 2 runes and 1 moonstone (different types)");
19	
20	    // --- Item-specific modifiers ---
21	    it.todo("should add 50% cursed surcharge to the cursed item base premium only");
22	    it.todo("should add 30% high-enchantment surcharge for enchantment level 5 or above");
23	    it.todo("should not add high-enchantment surcharge for enchantment level 4");
24	    it.todo("should apply both cursed and high-enchantment surcharges to the same item");
25	
26	    // --- Policy-wide modifiers ---
27	    it.todo("should apply 20% loyalty discount for customers with 2 or more years");
28	    it.todo("should apply 10% first-insurance surcharge on every quote");
29	    it.todo("should apply 15% follow-up discount on the second and subsequent quotes");
30	
31	    // --- Multi-item policies ---
32	    it.todo("should sum base premiums of multiple different items before applying policy-wide modifiers");
33	    it.todo("should apply item-specific surcharges only to the affected item in a multi-item policy");
34	
35	    // --- Integration examples from spec ---
36	    it.todo("should return 165 G for a newcomer with a cursed sword");
37	    it.todo("should return 160 G for a long-standing customer's second contract with a cursed enchanted sword");
38	
39	    // --- Rounding ---
40	    it.todo("should round premiums up in MHPCO's favor");
41	  });
42	
43	  describe("claim", () => {
44	    // --- Standard reimbursement ---
45	    it.todo("should reimburse damage minus 100 G deductible for a regular item");
46	
47	    // --- Dragon material ---
48	    it.todo("should fully reimburse damage to dragon-material items minus deductible when enchantment is below 8");
49	
50	    // --- High enchantment ---
51	    it.todo("should reimburse at 50% of damage amount minus deductible for enchantment 8 or above");
52	
53	    // --- Both clauses ---
54	    it.todo("should apply 50% rule when both dragon-material and enchantment >= 8 apply");
55	
56	    // --- Deductible per item ---
57	    it.todo("should apply 100 G deductible per damaged item independently");
58	
59	    // --- Cap ---
60	    it.todo("should cap total payout at twice the insurance sum");
61	    it.todo("should track remaining cap across multiple claims on the same policy");
62	
63	    // --- Rounding ---
64	    it.todo("should round payouts down in MHPCO's favor");
65	  });
